import Foundation

class NetworkingLayer {
    private let baseURL = URL(string: "https://api.example.com")!
    
    func fetchUserData(completion: @escaping ([String: Any]?, Error?) -> Void) {
        guard let url = baseURL.appendingPathComponent("users") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            guard let data = data else { return completion(nil, error) }
            
            do {
                let decoder = JSONDecoder()
                let userData = try decoder.decode([String: Any].self, from: data)
                completion(userData, nil)
            } catch {
                completion(nil, error)
            }
        }.resume()
    }
    
    func authenticateUser(username: String, password: String, completion: @escaping (Bool?, Error?) -> Void) {
        guard let url = baseURL.appendingPathComponent("users/authenticate") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let jsonData = try? JSONSerialization.data(withJSONObject: ["username": username, "password": password])
        request.httpBody = jsonData
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            guard let data = data else { return completion(nil, error) }
            
            do {
                let decoder = JSONDecoder()
                let authenticationResponse = try decoder.decode([String: Any].self, from: data)
                if let isAuthenticated = authenticationResponse["isAuthenticated"] as? Bool {
                    completion(isAuthenticated, nil)
                } else {
                    completion(nil, NSError(domain: "NetworkingLayer", code: 0, userInfo: [NSLocalizedDescriptionKey: "Invalid response from server"]))
                }
            } catch {
                completion(nil, error)
            }
        }.resume()
    }
}